export const formatINR = (value) => {
  const amount = Number(value) || 0;
  return new Intl.NumberFormat('en-IN', {
    style: 'currency',
    currency: 'INR',
    maximumFractionDigits: 2,
  }).format(amount);
};

export const getProductImage = (item) => {
  if (item?.image_url) return item.image_url;
  const name = encodeURIComponent(item?.name || item?.product_name || 'product');
  // Non-random deterministic placeholder keyed by name.
  return `https://placehold.co/600x450/png?text=${name}`;
};
